const arr = [3, 9, 2, 15, 7, 22, 1];

// 方法1：Math.max + 展开运算符
const max1 = Math.max(...arr);
console.log(max1);  // 22

// 方法2：reduce
const max2 = arr.reduce((max, cur) => cur > max ? cur : max, -Infinity);
console.log(max2);  // 22

// 方法3：for 循环
let max3 = arr[0];
for (let i = 1; i < arr.length; i++) {
    if (arr[i] > max3) max3 = arr[i];
}
console.log(max3);  // 22

// 基础柯里化：将 add(a,b,c) 转为 add(a)(b)(c)
function curry(fn) {
    return function curried(...args) {
        if (args.length >= fn.length) {
            return fn.apply(this, args);
        } else {
            return function(...nextArgs) {
                return curried.apply(this, args.concat(nextArgs));
            };
        }
    };
}

// 原始求和函数
function sum(a, b, c) {
    return a + b + c;
}

const curriedSum = curry(sum);
console.log(curriedSum(1)(2)(3));  // 6
console.log(curriedSum(1, 2)(3));  // 6
console.log(curriedSum(1)(2, 3));  // 6

// 进阶：无限柯里化（累加）
function add(...args) {
    const sum = args.reduce((a, b) => a + b, 0);
    const inner = (...next) => add(sum, ...next);
    inner.valueOf = () => sum;  // 用于隐式转换
    return inner;
}

console.log(add(1)(2)(3).valueOf());   // 6
console.log(add(1,2)(3,4)(5).valueOf()); // 15
